  async function updateMatchStatusForUser(userId, matchId, nextStatus) {
    const match = await getAccessibleMatchForUser(userId, matchId);
    if (!match) {
      throw new AppError(404, "match_not_found");
    }
    const role = await getRoleForUser(userId, match.channel_link_id);
    if (!role || !canCreateMatches(role)) {
      throw new AppError(403, "insufficient_permissions");
    }
    const previousStatus = match.status;
    const timestamp = nowIso2();
    const chatEnabledUntil = nextStatus === "paused" ? new Date(Date.now() + MATCH_PAUSE_GRACE_MS).toISOString() : null;
    if (nextStatus === "live") {
      const existingLive = await first(
        db,
        `SELECT id
          FROM matches
          WHERE channel_link_id = ?
            AND status = 'live'
            AND id != ?
          LIMIT 1`,
        match.channel_link_id,
        matchId
      );
      if (existingLive) {
        throw new AppError(409, "live_match_exists");
      }
    }
    await run(
      db,
      `UPDATE matches
        SET status = ?,
            chat_enabled_until = ?,
            updated_at = ?
        WHERE id = ?`,
      nextStatus,
      chatEnabledUntil,
      timestamp,
      matchId
    );
    await syncChatTargetsForChannelLink(match.channel_link_id);
    await writeAuditLog({
      action: "match.status.updated",
      actorUserId: userId,
      matchId,
      channelLinkId: match.channel_link_id,
      payload: {
        fromStatus: previousStatus,
        toStatus: nextStatus
      }
    });
    const summary = await getMatchSummaryById(matchId);
    if (!summary) {
      throw new AppError(404, "match_not_found");
    }
    return summary;
  }
